interceptor.preaction:

Util u=new Util();
String ip=u.getRemoteIP(rrequest);
rrequest.getRequest().setAttribute("reqKey2", ip);

update.value:


	UPDATE IBS.T3_COMMISSION_RATIO
	SET	
		YEAR=@{YEAR}
       ,BRANCH_ORG_ID=@{BRANCH_ORG_ID}
       ,PSTN_TYPE=@{PSTN_TYPE}
       ,SUB_PSTN_TYPE=@{SUB_PSTN_TYPE}
	   ,COMMISSION =@{COMMISSION}
       ,MODIFY_PEOPLE=#{user_id}
       ,MODIFY_TIME=#{current_time}
       ,MODIFY_IP=#{ip}
       ,REMARK=REMARK||@{REMARK1}
	WHERE BRANCH_ORG_ID = @{BRANCH_ORG_ID__old} 
	AND YEAR=@{YEAR__old}
	AND EFF_FLAG=1
	AND PSTN_TYPE=@{PSTN_TYPE__old}
	AND SUB_PSTN_TYPE=@{SUB_PSTN_TYPE__old}
	AND COMMISSION =@{COMMISSION__old}
	;

sql.delete:






UPDATE IBS.T3_COMMISSION_RATIO
SET EFF_FLAG=0
	,MODIFY_PEOPLE=#{user_id}
	,MODIFY_TIME=#{current_time}
	,MODIFY_IP=#{ip}
	,REMARK=REMARK||@{REMARK1}
	WHERE BRANCH_ORG_ID = @{BRANCH_ORG_ID__old} 
	AND YEAR=@{YEAR__old}
	AND EFF_FLAG=1
	AND PSTN_TYPE=@{PSTN_TYPE__old}
	AND SUB_PSTN_TYPE=@{SUB_PSTN_TYPE__old}
	AND COMMISSION =@{COMMISSION__old}
	;
